from haystack import component

import re

@component
class PIILeakDetector:
    @component.output_types(detected=bool, entities=list)
    def run(self, text: str):
        patterns = {
            'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
            'phone': r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b',
            'api_key': r'(?i)(key|token|secret)[\s:=]+[a-zA-Z0-9]{20,}'
        }

        entities = []
        for type_, pattern in patterns.items():
            matches = re.findall(pattern, text)
            if matches:
                entities.extend([{'type': type_, 'value': m} for m in matches])

        return {'detected': bool(entities), 'entities': entities}

from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever

from typing import List

class SafeRetriever(InMemoryEmbeddingRetriever):
    SENSITIVE_FIELDS = {'email', 'phone', 'ssn', 'api_key'}

    def run(self, query_embedding: List[float], top_k: int = 5):
        result = super().run(query_embedding=query_embedding, top_k=top_k)

        filtered_docs = []
        for doc in result['documents']:
            has_sensitive = any(
                field in str(doc.meta).lower() 
                for field in self.SENSITIVE_FIELDS
            )
            if not has_sensitive:
                filtered_docs.append(doc)

        result['documents'] = filtered_docs[:top_k]
        return result

from haystack import component
import json

@component
class EntropyLeakDetector:
    @component.output_types(leak_risk=float, suspicious_patterns=list)
    def run(self, response: str):
        score = 0
        patterns = []

        # High entropy strings often indicate base64/API keys
        entropy = -sum(p * (c / len(response)) for c in set(response) 
                      for p in [response.count(c)/len(response)])

        if entropy > 4.5:  # Base64-like entropy
            score += 0.8
            patterns.append('high_entropy')

        # JSON-like structures in responses
        try:
            json.loads(response)
            score += 0.6
            patterns.append('json_structure')
        except:
            pass

        return {'leak_risk': score, 'suspicious_patterns': patterns}

