from haystack import component
import re

@component
class PIIRedactor:
    @component.output_types(cleaned_text=str, redacted_count=int)
    def run(self, text: str):
        patterns = [
            (r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]'),
            (r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b', '[PHONE]'),
            (r'(?i)(key|token|secret)[\s:=]+[a-zA-Z0-9]{20,}', '[CREDENTIAL]')
        ]

        cleaned = text
        redacted_count = 0
        for pattern, replacement in patterns:
            matches = re.findall(pattern, cleaned)
            redacted_count += len(matches)
            cleaned = re.sub(pattern, replacement, cleaned)

        return {'cleaned_text': cleaned, 'redacted_count': redacted_count}

from haystack import Document

class SafeDocumentProcessor:
    SENSITIVE_KEYS = {'email', 'phone', 'password', 'api_key', 'ssn'}

    @staticmethod
    def sanitize_document(doc: Document) -> Document:
        if doc.meta:
            cleaned_meta = {
                k: v for k, v in doc.meta.items()
                if k.lower() not in SafeDocumentProcessor.SENSITIVE_KEYS
            }
            doc.meta = cleaned_meta

        # Sanitize content
        doc.content = SafeDocumentProcessor.redact_pii(doc.content)
        return doc

    @staticmethod
    def redact_pii(text: str) -> str:
        # Simple PII redaction
        text = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', text)
        return re.sub(r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b', '[PHONE]', text)
